{
  "options": [
    {
      "text": "拿起那封信，对着光查看封蜡和纸张的细节",
      "actionId": null
    },
    {
      "text": "直接问卡琳娜：“你知道谁会送这封信来吗？”",
      "actionId": null
    },
    {
      "text": "转头看向沙发上的黑猫：“你怎么看？”",
      "actionId": null
    },
    {
      "text": "放下信，看向卡琳娜：“看来有人不想让我们安安静静地谈正事。先说说敏特的事？也许这两封信有关。”",
      "actionId": "choice:说明敏特的事"
    }
  ]
}
